#!/bin/bash

# ==================== Setup Domain từ Namecheap ====================
# Script hướng dẫn setup domain canhnq.online từ Namecheap với Route 53
# ====================================================================

set -e

echo "🌐 Setup Domain canhnq.online từ Namecheap"
echo "=========================================="

# Colors
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
BLUE='\033[0;34m'
NC='\033[0m'

DOMAIN="canhnq.online"

echo ""
echo -e "${BLUE}Step 1: Tạo Route 53 Hosted Zone${NC}"
echo "----------------------------------------"

# Check if hosted zone exists
EXISTING_ZONE=$(aws route53 list-hosted-zones --query "HostedZones[?Name=='${DOMAIN}.'].[Id]" --output text 2>/dev/null || echo "")

if [ ! -z "$EXISTING_ZONE" ]; then
    echo -e "${GREEN}✅ Hosted zone đã tồn tại: $EXISTING_ZONE${NC}"
    ZONE_ID=$(echo $EXISTING_ZONE | cut -d'/' -f3)
else
    echo -e "${YELLOW}⚠️  Hosted zone chưa tồn tại. Tạo mới...${NC}"
    
    # Create hosted zone
    CALLER_REF=$(date +%s)
    RESPONSE=$(aws route53 create-hosted-zone \
        --name $DOMAIN \
        --caller-reference $CALLER_REF \
        --hosted-zone-config Comment="VSL Platform" 2>&1)
    
    if [ $? -eq 0 ]; then
        ZONE_ID=$(echo $RESPONSE | grep -oP '"Id":\s*"/hostedzone/\K[^"]+' || echo "")
        echo -e "${GREEN}✅ Hosted zone đã được tạo: $ZONE_ID${NC}"
    else
        echo -e "${RED}❌ Lỗi khi tạo hosted zone${NC}"
        echo "$RESPONSE"
        exit 1
    fi
fi

# Get Name Servers
echo ""
echo -e "${BLUE}Step 2: Lấy Name Servers từ Route 53${NC}"
echo "----------------------------------------"

NAME_SERVERS=$(aws route53 get-hosted-zone --id $ZONE_ID --query "DelegationSet.NameServers" --output text 2>/dev/null)

if [ -z "$NAME_SERVERS" ]; then
    echo -e "${RED}❌ Không thể lấy Name Servers${NC}"
    exit 1
fi

echo -e "${GREEN}✅ Name Servers từ Route 53:${NC}"
echo "$NAME_SERVERS" | tr '\t' '\n' | nl

